import{_ as i,c as a,o as t,aN as n}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"Dockerfile 写法","description":"","frontmatter":{},"headers":[],"relativePath":"09.容器化/05-Dockerfile写法.md","filePath":"09.容器化/05-Dockerfile写法.md","lastUpdated":null}'),e={name:"09.容器化/05-Dockerfile写法.md"};function p(l,s,h,k,d,r){return t(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="dockerfile-写法" tabindex="-1">Dockerfile 写法 <a class="header-anchor" href="#dockerfile-写法" aria-label="Permalink to &quot;Dockerfile 写法&quot;">​</a></h1><p>Dockerfile 是镜像构建的说明书。写得清楚，镜像就能复现；写得随意，后面发布、回滚、扫描和排查都会变成猜。写 Dockerfile 时先保证可复现，再考虑瘦身——可复现是发布和回滚的底线。</p><h2 id="基本结构和指令" tabindex="-1">基本结构和指令 <a class="header-anchor" href="#基本结构和指令" aria-label="Permalink to &quot;基本结构和指令&quot;">​</a></h2><p>一个常见的 Python 应用 Dockerfile：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 固定基础镜像版本，避免 latest 指向变化导致构建结果漂移</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> python:3.12-slim</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设置工作目录，后续 COPY/RUN/CMD 都以此为基准</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 先复制依赖文件，利用构建缓存——依赖变化少，代码变化多</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> requirements.txt .</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装依赖后清理 pip 缓存，减少镜像层体积</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pip install --no-cache-dir -r requirements.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 再复制应用代码，代码变更时只影响从这一行开始的层</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> . .</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 声明容器内服务端口，真正暴露还要靠 docker run -p 或 Compose ports</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">EXPOSE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 8000</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 exec 形式，进程作为 PID 1 能正确收到 SIGTERM</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;python&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app.py&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>常用指令：</p><table tabindex="0"><thead><tr><th>指令</th><th>作用</th></tr></thead><tbody><tr><td><code>FROM</code></td><td>指定基础镜像，必须是第一条指令</td></tr><tr><td><code>WORKDIR</code></td><td>设置工作目录，后续指令的相对路径以此为基准</td></tr><tr><td><code>COPY</code></td><td>从构建上下文复制文件到镜像</td></tr><tr><td><code>RUN</code></td><td>构建时执行命令，每个 RUN 生成一层</td></tr><tr><td><code>ENV</code></td><td>设置环境变量，会留在镜像层和容器运行时</td></tr><tr><td><code>EXPOSE</code></td><td>声明端口，纯文档性质——真正暴露靠运行时 <code>-p</code></td></tr><tr><td><code>USER</code></td><td>指定运行用户</td></tr><tr><td><code>ENTRYPOINT</code></td><td>固定入口程序</td></tr><tr><td><code>CMD</code></td><td>默认启动参数或命令</td></tr></tbody></table><p>Dockerfile 不是 shell 脚本。每个 <code>RUN</code> 生成一层，文件复制和删除要考虑中间产物有没有留在最终镜像里。</p><h2 id="copy-和-add-的区别" tabindex="-1">COPY 和 ADD 的区别 <a class="header-anchor" href="#copy-和-add-的区别" aria-label="Permalink to &quot;COPY 和 ADD 的区别&quot;">​</a></h2><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app.py /app/app.py</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> config/ /app/config/</span></span></code></pre></div><p><code>ADD</code> 额外支持自动解压 tar 和从 URL 添加文件。语义上 <code>COPY</code> 更直接，只有确认需要自动解压本地 tar 包时才用 <code>ADD</code>。日常构建优先 <code>COPY</code>。</p><h2 id="run-合并与构建缓存" tabindex="-1">RUN 合并与构建缓存 <a class="header-anchor" href="#run-合并与构建缓存" aria-label="Permalink to &quot;RUN 合并与构建缓存&quot;">​</a></h2><p>安装系统包时把更新索引、安装、清理缓存放在同一个 <code>RUN</code> 里：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> apt-get update \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &amp;&amp; apt-get install -y --no-install-recommends curl ca-certificates \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &amp;&amp; rm -rf /var/lib/apt/lists/*</span></span></code></pre></div><p>拆成多个 <code>RUN</code> 的话，即使后面删除了缓存，前面的层里仍然可能保留缓存文件——镜像体积就白白大了。</p><p>构建缓存跟指令顺序强相关。Docker 逐条执行指令，如果某条指令的结果在缓存中（前一条指令相同、本条指令内容相同），就直接复用缓存。所以通常先 COPY 依赖声明（变化少），再安装依赖，最后 COPY 应用代码（变化多）——这样代码变更不会让前面的依赖安装层缓存失效。</p><h2 id="cmd-和-entrypoint" tabindex="-1">CMD 和 ENTRYPOINT <a class="header-anchor" href="#cmd-和-entrypoint" aria-label="Permalink to &quot;CMD 和 ENTRYPOINT&quot;">​</a></h2><p><code>CMD</code> 提供默认命令，可以被 <code>docker run</code> 后面的命令覆盖：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;nginx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-g&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;daemon off;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><code>ENTRYPOINT</code> 做固定入口，<code>CMD</code> 做默认参数：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ENTRYPOINT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;python&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;worker.py&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;--log-level=info&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>运行时：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo-worker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --log-level=debug</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 只覆盖 CMD 参数，ENTRYPOINT 不变</span></span></code></pre></div><p>服务类镜像的主进程必须前台运行。把进程丢到后台后，容器的 PID 1 退出，容器也跟着退出。这是容器和虚拟机的一个关键差异——容器没有 init 系统去接管孤儿进程。</p><h2 id="非-root-用户" tabindex="-1">非 root 用户 <a class="header-anchor" href="#非-root-用户" aria-label="Permalink to &quot;非 root 用户&quot;">​</a></h2><p>很多官方镜像默认 root 运行。业务服务能不用 root 就不用：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> python:3.12-slim</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建固定 UID/GID，方便和宿主机挂载目录对齐权限</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> groupadd -g 10001 app \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    &amp;&amp; useradd -u 10001 -g app -s /usr/sbin/nologin app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> requirements.txt .</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pip install --no-cache-dir -r requirements.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --chown=app:app . .</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">USER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;python&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app.py&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>容器内 root 不等于宿主机 root，但风险仍然更高。挂载宿主机目录、开启特权容器、Docker socket 暴露出来时，root 的风险会被放大。</p><h2 id="多阶段构建" tabindex="-1">多阶段构建 <a class="header-anchor" href="#多阶段构建" aria-label="Permalink to &quot;多阶段构建&quot;">​</a></h2><p>多阶段构建把编译和运行环境拆成两个阶段。前一阶段编译，后一阶段只复制运行需要的文件，编译工具、源码缓存、测试文件不会进入最终镜像：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第一阶段：编译</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> golang:1.22 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> builder</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /src</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> go.mod go.sum ./</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> go mod download</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> . .</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CGO_ENABLED=0 GOOS=linux go build -o /out/app ./cmd/app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第二阶段：只保留运行文件</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> alpine:3.20</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> adduser -D -u 10001 app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --from=builder /out/app /usr/local/bin/app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">USER</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ENTRYPOINT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/usr/local/bin/app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>运维上看，镜像小了，拉取更快，漏洞扫描面也更少——基础的 golang 编译镜像有几百 MB，最终运行镜像可能只有十几 MB。</p><h2 id="健康检查" tabindex="-1">健康检查 <a class="header-anchor" href="#健康检查" aria-label="Permalink to &quot;健康检查&quot;">​</a></h2><p><code>HEALTHCHECK</code> 指令在容器内周期性执行命令判断服务是否正常：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">HEALTHCHECK</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --interval=30s --timeout=3s --retries=3 \\</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> curl -fsS http://127.0.0.1:8080/health || exit 1</span></span></code></pre></div><p>检查命令在容器内部执行。镜像里没有 <code>curl</code> 就会失败，所以要确保检查工具存在于镜像中。健康检查路径要轻，不适合塞复杂数据库查询——处理健康检查本身不应该成为负载。</p><h2 id="镜像瘦身的方向" tabindex="-1">镜像瘦身的方向 <a class="header-anchor" href="#镜像瘦身的方向" aria-label="Permalink to &quot;镜像瘦身的方向&quot;">​</a></h2><table tabindex="0"><thead><tr><th>做法</th><th>说明</th></tr></thead><tbody><tr><td>使用 slim/alpine/distroless</td><td>减少基础系统体积</td></tr><tr><td>多阶段构建</td><td>编译依赖不进最终镜像</td></tr><tr><td>清理包管理缓存</td><td>避免 apt/yum 缓存留在层里</td></tr><tr><td><code>.dockerignore</code></td><td>排除源码目录里无关文件</td></tr><tr><td>固定依赖版本</td><td>减少不可复现构建</td></tr></tbody></table><p>Alpine 很小，但它用的是 musl libc 而不是 glibc。某些程序依赖 glibc 特定行为时，在 Alpine 上会出问题。镜像瘦身不是只看体积数字，线上稳定性比镜像小 20MB 重要。</p><h2 id="buildkit-的缓存挂载和密钥" tabindex="-1">BuildKit 的缓存挂载和密钥 <a class="header-anchor" href="#buildkit-的缓存挂载和密钥" aria-label="Permalink to &quot;BuildKit 的缓存挂载和密钥&quot;">​</a></h2><p>BuildKit 是当前 Docker 的默认构建后端，支持更好的缓存、secret mount 和 SSH mount。</p><p>构建缓存挂载——依赖下载缓存只用于构建过程，不进入最终镜像：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># syntax=docker/dockerfile:1.7</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> python:3.12-slim</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> requirements.txt .</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># pip 缓存挂载到 /root/.cache/pip，构建完成后不留在镜像里</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --mount=type=cache,target=/root/.cache/pip \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pip install -r requirements.txt</span></span></code></pre></div><p>secret mount——构建时需要的 Token、密码不写进 Dockerfile 的 <code>ENV</code> 或 <code>ARG</code>：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># syntax=docker/dockerfile:1.7</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> alpine:3.20</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /run/secrets/npm_token 只在这一条 RUN 期间存在，不会进入最终镜像层</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --mount=type=secret,id=npm_token \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    cat /run/secrets/npm_token &gt;/dev/null</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> id=npm_token,src=/opt/secret/npm_token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/demo/app:1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>SSH mount——构建时需要访问私有 Git 仓库：</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># syntax=docker/dockerfile:1.7</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> alpine/git:2.45</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用宿主机 SSH agent，不把私钥 COPY 进镜像</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --mount=type=ssh \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    git ls-remote git@example.com:ops/private-repo.git</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> registry.example.com/demo/git-check:1.0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div><p>&quot;密钥不进镜像层&quot;应该当成 Dockerfile 的硬检查项。<code>docker history</code> 里能看到的内容，就不该出现密码、Token、私钥路径和内部仓库凭据。</p><h2 id="dockerfile-检查项" tabindex="-1">Dockerfile 检查项 <a class="header-anchor" href="#dockerfile-检查项" aria-label="Permalink to &quot;Dockerfile 检查项&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>检查点</th></tr></thead><tbody><tr><td>基础镜像</td><td>是否固定版本，来源是否可信</td></tr><tr><td>构建缓存</td><td>依赖层和代码层顺序是否合理</td></tr><tr><td>镜像大小</td><td>是否清理缓存，是否使用多阶段构建</td></tr><tr><td>用户</td><td>是否默认 root，挂载目录的 UID/GID 是否明确</td></tr><tr><td>启动</td><td>主进程是否前台运行，exec 形式是否正确</td></tr><tr><td>密钥</td><td>是否被 COPY 进镜像，构建凭据是否使用 secret/SSH mount</td></tr><tr><td>健康检查</td><td>检查命令是否存在，路径是否轻量</td></tr></tbody></table>`,52)])])}const E=i(e,[["render",p]]);export{c as __pageData,E as default};
